INSERT INTO "_content_index" VALUES('index/index.yml','Hi! I''m Sean Erick Ramones, a Software Engineer','{"title":"About Me","description":"As a full-stack software engineer with over 7 years of experience, I specialize in building modern, performant web applications with a strong focus on usability and design consistency.\nMy approach blends technical depth with user-centered thinking—translating complex ideas into scalable, accessible digital products that balance functionality, performance, and great user experience.\n"}','{"title":"Latest Articles","description":"Some of my recent thoughts"}','{"seo":{"title":"Sean Erick C. Ramones | Full-stack Software Engineer","description":"Welcome to my portfolio! I''m Sean Erick Ramones, and I build digital solutions that are both beautiful and functional."},"profileImage":{"src":"/avatars/profile-image-1.png","alt":"Profile image of Sean Erick Ramones"},"title":"Hi! I''m Sean Erick Ramones, a Software Engineer","description":"I create intuitive, scalable applications where design meets functionality, turning complex ideas into seamless user experiences.","snsLinks":[{"icon":"i-simple-icons-linkedin","to":"https://www.linkedin.com/in/sean-erick-ramones-102a64192","target":"_blank","aria-label":"Sean Erick Ramones on Linkedin"},{"icon":"i-simple-icons-github","to":"https://github.com/sean-erick-ramones","target":"_blank","aria-label":"Sean Erick Ramones on GitHub"},{"icon":"i-simple-icons-x","to":"https://x.com/ramones_sean","target":"_blank","aria-label":"Nuxt on X"},{"icon":"i-simple-icons-instagram","to":"https://www.instagram.com/sean.e.ramz","target":"_blank","aria-label":"Sean Erick Ramones on Instagram"}],"hero":{"links":[{"label":"Download Resume","to":"/documents/sean-ramones-resume.pdf","target":"_blank","color":"neutral","variant":"outline","icon":"i-lucide-download","download":"Resume - Sean Erick Ramones"}],"images":[{"src":"/hero/nodejs.png","alt":"Node.js logo"},{"src":"/hero/vue.png","alt":"Vue.js logo"},{"src":"/hero/nuxt.png","alt":"Nuxt logo"},{"src":"/hero/react.png","alt":"React logo"},{"src":"/hero/postgres.png","alt":"PostgreSQL logo"},{"src":"/hero/supabase.png","alt":"Supabase logo"},{"src":"/hero/vite.png","alt":"Vite logo"},{"src":"/hero/github.png","alt":"GitHub logo"},{"src":"/hero/vercel.png","alt":"Vercel logo"},{"src":"/hero/cloudflare.png","alt":"Cloudflare logo"},{"src":"/hero/git.png","alt":"Git logo"},{"src":"/hero/jira.png","alt":"Jira logo"},{"src":"/hero/github-copilot.png","alt":"GitHub Copilot logo"}]},"now":{"openTo":["Full-time","Contract","Remote (UTC+8 overlap)"],"available":true,"meetingLink":"https://calendly.com/seancramones/15-min-quick-chat"},"about":{"title":"About Me","description":"As a full-stack software engineer with over 7 years of experience, I specialize in building modern, performant web applications with a strong focus on usability and design consistency.\nMy approach blends technical depth with user-centered thinking—translating complex ideas into scalable, accessible digital products that balance functionality, performance, and great user experience.\n"},"experience":{"title":"Work Experience","items":[{"position":"Full-stack Software Engineer","date":"May 2019 - Present","company":{"name":"Miller Development AB","logo":"i-lucide-code-xml","url":"https://millerdevelopment.se"},"description":"Led full-stack development across international clients, progressing from mid-level to Vue SME while building scalable dashboards, HR SaaS products, and ML-integrated platforms using Vue, Nuxt, Node.js, FastAPI, and serverless architecture.","index":2},{"position":"Full-stack Software Developer","date":"Jun 2018 - Apr 2019","company":{"name":"SCI Global Services Inc.","logo":"i-lucide-flask-conical","url":"http://sciglobalservices.com/"},"description":"Developed B2B websites and digital marketing solutions for laboratory and medical markets, delivering full-stack web applications with integrated graphic design and interactive media.","index":1},{"position":"Software Developer (Contractual)","date":"May 2023 - Jan 2024","company":{"name":"Better Trade Off Ltd.","logo":"i-simple-icons-angular","url":"https://www.bettertradeoff.com"},"description":"Spearheaded AngularJS to Angular v12+ migration strategy by introducing reusable Web Components and modernizing onboarding portals, login systems, and admin dashboards to reduce technical debt.","index":3}]},"blog":{"title":"Latest Articles","description":"Some of my recent thoughts"},"testimonials":{"title":"Testimonials","description":"Feedback from colleagues and clients.","items":[{"quote":"I’ve had the pleasure of working with Sean for four years. During that time, he’s been my go-to person whenever I have questions about frontend development. While I’ve been more focused on backend work, I’ve always admired how proficient Sean is with frontend technologies and how he consistently stays up to date with the latest tools and best practices.\n\nSean is easy to work with, approachable, and always willing to help. He explains things clearly and patiently, making collaboration smooth and productive. He brings both technical skill and a great attitude to the team, which makes him a valuable teammate and a great person to work with.\n\nI highly recommend Sean to any team looking for a skilled frontend developer who’s not only technically strong but also genuinely collaborative and supportive.\n","author":{"name":"Andrew Vincoy","description":"Tech Lead | Software Engineer @ Miller Development","to":"https://www.linkedin.com/in/andrew-vincoy-226014169/","avatar":{"src":"/avatars/testimonials/andrew-vincoy-profile-image.jpeg"}}},{"quote":"I had the privilege of working with Sean Ramones on multiple projects at Miller Development, where he consistently stood out as a dependable and capable Full Stack Developer.\n\nSean combines strong technical skills with an impressive ability to adapt, collaborate, and deliver high-quality results. He approaches every task with ownership and attention to detail, ensuring that his work not only meets requirements but also contributes to the overall stability and performance of the product.\n\nI strongly recommend Sean for any software development role. He is the kind of developer who not only delivers excellent work but also inspires collaboration and continuous improvement in those around him.\n","author":{"name":"Asa Bain","description":"Tech Lead | Senior Software Engineer @ Miller Development","to":"https://www.linkedin.com/in/asa-bain-6bb980119/","avatar":{"src":"/avatars/testimonials/asa-bain-profile-image.jpeg"}}}]},"faq":{"title":"Frequently Asked Questions","description":"Answers to common questions about how I work, collaborate, and what I’m looking for next.","categories":[{"title":"Work & Collaboration","questions":[{"label":"What kinds of projects do you focus on?","content":"I build full‑stack web applications, dashboards, and SaaS platforms with data‑rich, user‑friendly interfaces. On the frontend I primarily use Vue/Nuxt (and React when needed). On the backend I work with Node.js and FastAPI, with PostgreSQL/Supabase for data, and modern serverless/cloud platforms like Vercel and Cloudflare.\n"},{"label":"How do you ensure scalability and code quality?","content":"I favor type‑safe code (TypeScript), clear architecture and modular components, automated testing where it matters, and performance profiling. I document decisions, use code reviews, and set up CI to keep quality high as the product grows.\n"},{"label":"Do you work on greenfield or existing codebases?","content":"Both. I enjoy greenfield builds and I’m experienced in migrations and modernization—e.g., leading an AngularJS → Angular upgrade using Web Components while reducing technical debt.\n"}]},{"title":"Compensation & Availability","questions":[{"label":"How do you approach compensation discussions?","content":"Compensation depends on the role’s scope, responsibilities, and overall package. I prefer to align on impact and expectations first, then discuss a market‑competitive offer accordingly. I’m also comfortable aligning with established salary bands and total compensation frameworks.\n"},{"label":"Are you open to contract or freelance work?","content":"Yes—I''m open to full‑time roles as well as contract engagements. For contracts, I prefer clearly defined scopes, deliverables, and timelines.\n"},{"label":"What is your availability and timezone compatibility?","content":"I primarily work in UTC+8 and can align to overlapping hours for teams in other timezones. I’m comfortable with remote and hybrid collaboration, async workflows, and scheduled syncs for key milestones.\n"},{"label":"What roles are you looking for?","content":"Primarily **Full‑stack Software Engineer** or **Frontend Engineer (Vue/Nuxt)** roles. I’m comfortable working with React when needed and I’m open to senior IC positions, hands‑on tech leadership, and platform‑focused full‑stack work.\n"},{"label":"What’s your notice period?","content":"Typically **1–3 weeks**, depending on active workload and handover requirements. I’ll align timelines to ensure a smooth transition.\n"}]},{"title":"About Me","questions":[{"label":"What do you enjoy outside of work?","content":"- Running\n- Cross‑fit training\n- Watching anime\n- Reading Japanese manga/light novels\n- Playing MOBA games (Dota 2) and relaxing games (Stardew Valley)\n- Driving and exploring new places\n- Coffee! Whether it''s brewing pour-over or using the espresso machine and creating (terrible) latter art.\n"},{"label":"What motivates your work as an engineer?","content":"Turning complex ideas into scalable, well‑designed products that feel effortless to use. I love shaping systems where design consistency, performance, and developer experience work together.\n"},{"label":"What tech do you prefer working with?","content":"Vue 3, Nuxt, Node.js, FastAPI, PostgreSQL/Supabase, and modern tooling (Vite, GitHub, CI/CD). I’m pragmatic and will choose the right tool for the job.\n"}]}]}}','I create intuitive, scalable applications where design meets functionality, turning complex ideas into seamless user experiences.','{"title":"Work Experience","items":[{"position":"Full-stack Software Engineer","date":"May 2019 - Present","company":{"name":"Miller Development AB","logo":"i-lucide-code-xml","url":"https://millerdevelopment.se"},"description":"Led full-stack development across international clients, progressing from mid-level to Vue SME while building scalable dashboards, HR SaaS products, and ML-integrated platforms using Vue, Nuxt, Node.js, FastAPI, and serverless architecture.","index":2},{"position":"Full-stack Software Developer","date":"Jun 2018 - Apr 2019","company":{"name":"SCI Global Services Inc.","logo":"i-lucide-flask-conical","url":"http://sciglobalservices.com/"},"description":"Developed B2B websites and digital marketing solutions for laboratory and medical markets, delivering full-stack web applications with integrated graphic design and interactive media.","index":1},{"position":"Software Developer (Contractual)","date":"May 2023 - Jan 2024","company":{"name":"Better Trade Off Ltd.","logo":"i-simple-icons-angular","url":"https://www.bettertradeoff.com"},"description":"Spearheaded AngularJS to Angular v12+ migration strategy by introducing reusable Web Components and modernizing onboarding portals, login systems, and admin dashboards to reduce technical debt.","index":3}]}','yml','{"title":"Frequently Asked Questions","description":"Answers to common questions about how I work, collaborate, and what I’m looking for next.","categories":[{"title":"Work & Collaboration","questions":[{"label":"What kinds of projects do you focus on?","content":"I build full‑stack web applications, dashboards, and SaaS platforms with data‑rich, user‑friendly interfaces. On the frontend I primarily use Vue/Nuxt (and React when needed). On the backend I work with Node.js and FastAPI, with PostgreSQL/Supabase for data, and modern serverless/cloud platforms like Vercel and Cloudflare.\n"},{"label":"How do you ensure scalability and code quality?","content":"I favor type‑safe code (TypeScript), clear architecture and modular components, automated testing where it matters, and performance profiling. I document decisions, use code reviews, and set up CI to keep quality high as the product grows.\n"},{"label":"Do you work on greenfield or existing codebases?","content":"Both. I enjoy greenfield builds and I’m experienced in migrations and modernization—e.g., leading an AngularJS → Angular upgrade using Web Components while reducing technical debt.\n"}]},{"title":"Compensation & Availability","questions":[{"label":"How do you approach compensation discussions?","content":"Compensation depends on the role’s scope, responsibilities, and overall package. I prefer to align on impact and expectations first, then discuss a market‑competitive offer accordingly. I’m also comfortable aligning with established salary bands and total compensation frameworks.\n"},{"label":"Are you open to contract or freelance work?","content":"Yes—I''m open to full‑time roles as well as contract engagements. For contracts, I prefer clearly defined scopes, deliverables, and timelines.\n"},{"label":"What is your availability and timezone compatibility?","content":"I primarily work in UTC+8 and can align to overlapping hours for teams in other timezones. I’m comfortable with remote and hybrid collaboration, async workflows, and scheduled syncs for key milestones.\n"},{"label":"What roles are you looking for?","content":"Primarily **Full‑stack Software Engineer** or **Frontend Engineer (Vue/Nuxt)** roles. I’m comfortable working with React when needed and I’m open to senior IC positions, hands‑on tech leadership, and platform‑focused full‑stack work.\n"},{"label":"What’s your notice period?","content":"Typically **1–3 weeks**, depending on active workload and handover requirements. I’ll align timelines to ensure a smooth transition.\n"}]},{"title":"About Me","questions":[{"label":"What do you enjoy outside of work?","content":"- Running\n- Cross‑fit training\n- Watching anime\n- Reading Japanese manga/light novels\n- Playing MOBA games (Dota 2) and relaxing games (Stardew Valley)\n- Driving and exploring new places\n- Coffee! Whether it''s brewing pour-over or using the espresso machine and creating (terrible) latter art.\n"},{"label":"What motivates your work as an engineer?","content":"Turning complex ideas into scalable, well‑designed products that feel effortless to use. I love shaping systems where design consistency, performance, and developer experience work together.\n"},{"label":"What tech do you prefer working with?","content":"Vue 3, Nuxt, Node.js, FastAPI, PostgreSQL/Supabase, and modern tooling (Vite, GitHub, CI/CD). I’m pragmatic and will choose the right tool for the job.\n"}]}]}','{"links":[{"label":"Download Resume","to":"/documents/sean-ramones-resume.pdf","target":"_blank","color":"neutral","variant":"outline","icon":"i-lucide-download","download":"Resume - Sean Erick Ramones"}],"images":[{"src":"/hero/nodejs.png","alt":"Node.js logo"},{"src":"/hero/vue.png","alt":"Vue.js logo"},{"src":"/hero/nuxt.png","alt":"Nuxt logo"},{"src":"/hero/react.png","alt":"React logo"},{"src":"/hero/postgres.png","alt":"PostgreSQL logo"},{"src":"/hero/supabase.png","alt":"Supabase logo"},{"src":"/hero/vite.png","alt":"Vite logo"},{"src":"/hero/github.png","alt":"GitHub logo"},{"src":"/hero/vercel.png","alt":"Vercel logo"},{"src":"/hero/cloudflare.png","alt":"Cloudflare logo"},{"src":"/hero/git.png","alt":"Git logo"},{"src":"/hero/jira.png","alt":"Jira logo"},{"src":"/hero/github-copilot.png","alt":"GitHub Copilot logo"}]}','{}','true','{"openTo":["Full-time","Contract","Remote (UTC+8 overlap)"],"available":true,"meetingLink":"https://calendly.com/seancramones/15-min-quick-chat"}','/','{"src":"/avatars/profile-image-1.png","alt":"Profile image of Sean Erick Ramones"}','{"title":"Sean Erick C. Ramones | Full-stack Software Engineer","description":"Welcome to my portfolio! I''m Sean Erick Ramones, and I build digital solutions that are both beautiful and functional."}','[{"icon":"i-simple-icons-linkedin","to":"https://www.linkedin.com/in/sean-erick-ramones-102a64192","target":"_blank","aria-label":"Sean Erick Ramones on Linkedin"},{"icon":"i-simple-icons-github","to":"https://github.com/sean-erick-ramones","target":"_blank","aria-label":"Sean Erick Ramones on GitHub"},{"icon":"i-simple-icons-x","to":"https://x.com/ramones_sean","target":"_blank","aria-label":"Nuxt on X"},{"icon":"i-simple-icons-instagram","to":"https://www.instagram.com/sean.e.ramz","target":"_blank","aria-label":"Sean Erick Ramones on Instagram"}]','index','{"title":"Testimonials","description":"Feedback from colleagues and clients.","items":[{"quote":"I’ve had the pleasure of working with Sean for four years. During that time, he’s been my go-to person whenever I have questions about frontend development. While I’ve been more focused on backend work, I’ve always admired how proficient Sean is with frontend technologies and how he consistently stays up to date with the latest tools and best practices.\n\nSean is easy to work with, approachable, and always willing to help. He explains things clearly and patiently, making collaboration smooth and productive. He brings both technical skill and a great attitude to the team, which makes him a valuable teammate and a great person to work with.\n\nI highly recommend Sean to any team looking for a skilled frontend developer who’s not only technically strong but also genuinely collaborative and supportive.\n","author":{"name":"Andrew Vincoy","description":"Tech Lead | Software Engineer @ Miller Development","to":"https://www.linkedin.com/in/andrew-vincoy-226014169/","avatar":{"src":"/avatars/testimonials/andrew-vincoy-profile-image.jpeg"}}},{"quote":"I had the privilege of working with Sean Ramones on multiple projects at Miller Development, where he consistently stood out as a dependable and capable Full Stack Developer.\n\nSean combines strong technical skills with an impressive ability to adapt, collaborate, and deliver high-quality results. He approaches every task with ownership and attention to detail, ensuring that his work not only meets requirements but also contributes to the overall stability and performance of the product.\n\nI strongly recommend Sean for any software development role. He is the kind of developer who not only delivers excellent work but also inspires collaboration and continuous improvement in those around him.\n","author":{"name":"Asa Bain","description":"Tech Lead | Senior Software Engineer @ Miller Development","to":"https://www.linkedin.com/in/asa-bain-6bb980119/","avatar":{"src":"/avatars/testimonials/asa-bain-profile-image.jpeg"}}}]}','W19HYa6VtIYOGXW41BKPKv1d09b4PCq9AJTHcPm8gEg');
INSERT INTO "_content_projects" VALUES('projects/projects/pharus.yml','Pharus Tech AB','2019-09-01T00:00:00.000Z','Pharus Tech is an HR-tech company specializing in AI-driven data analytics and talent acquisition tools. Formerly known as JobAgent and is based in Stockholm.','yml','/projects/recent_projects_pharus.jpg','{"path":"/projects/pharus","body":{"title":"Pharus Tech AB","description":"Pharus Tech is an HR-tech company specializing in AI-driven data analytics and talent acquisition tools. Formerly known as JobAgent and is based in Stockholm.","image":"/projects/recent_projects_pharus.jpg","url":"https://tqnordic.com/tq-nordic-och-pharus-tech-gar-samman/","tags":["Vue.js","AI/ML","HR Tech","Talent Acquisition"],"date":"2019-09-01"}}','projects/pharus','["Vue.js","AI/ML","HR Tech","Talent Acquisition"]','https://tqnordic.com/tq-nordic-och-pharus-tech-gar-samman/','wBUTO05BOqy6HOK58cfrmQLPNDjoYaPgUiCrtB1ocr4');
INSERT INTO "_content_projects" VALUES('projects/projects/roommejts.yml','Roommejts AB','2025-06-01T00:00:00.000Z','Roommejts AB is focused on helping clients make smarter, data-driven decisions about interior layouts, renovations, and construction planning. By combining software and automation, they aim to simplify how architects, property managers, and designers plan and optimize living or office spaces.','yml','/projects/recent_projects_roommejts.jpg','{"path":"/projects/roommejts","body":{"title":"Roommejts AB","description":"Roommejts AB is focused on helping clients make smarter, data-driven decisions about interior layouts, renovations, and construction planning. By combining software and automation, they aim to simplify how architects, property managers, and designers plan and optimize living or office spaces.","image":"/projects/recent_projects_roommejts.jpg","url":"https://roommejts.se/","tags":["Vue.js","Node.js","Data Visualization","HR Tech"],"date":"2025-06-01"}}','projects/roommejts','["Vue.js","Node.js","Data Visualization","HR Tech"]','https://roommejts.se/','kcZUgocQyOsCR5eq3dMKG1nSGNb3T0gyiIuPNAgNrV4');
INSERT INTO "_content_projects" VALUES('projects/projects/sysarb.yml','Sysarb AB','2024-01-01T00:00:00.000Z','Sysarb AB is a Sweden-based HR-tech company with nearly 20 years of experience, positioning itself as one of Europe''s pioneering and leading voices in pay equity and pay transparency.','yml','/projects/recent_projects_sysarb.jpg','{"path":"/projects/sysarb","body":{"title":"Sysarb AB","description":"Sysarb AB is a Sweden-based HR-tech company with nearly 20 years of experience, positioning itself as one of Europe''s pioneering and leading voices in pay equity and pay transparency.","image":"/projects/recent_projects_sysarb.jpg","url":"https://sysarb.com/","tags":["Vue.js","Nuxt.js","HR Tech","Pay Equity"],"date":"2024-01-01"}}','projects/sysarb','["Vue.js","Nuxt.js","HR Tech","Pay Equity"]','https://sysarb.com/','jDltj3qz2XchyNh1gyVJPLgP8YMfif8MOpcYXUq-NdU');
INSERT INTO "_content_projects" VALUES('projects/projects/upplan.yml','Up Planner | Up Adviser','2023-04-01T00:00:00.000Z','Up is a free, user-friendly financial life-planning tool that allows anyone to craft and visualize their financial future through simple, interactive simulations.','yml','/projects/recent_projects_upplan.jpg','{"path":"/projects/upplan","body":{"title":"Up Planner | Up Adviser","description":"Up is a free, user-friendly financial life-planning tool that allows anyone to craft and visualize their financial future through simple, interactive simulations.","image":"/projects/recent_projects_upplan.jpg","url":"https://www.upplan.sg/up-adviser","tags":["Vue.js","Financial Planning","Data Visualization","SaaS"],"date":"2023-04-01"}}','projects/upplan','["Vue.js","Financial Planning","Data Visualization","SaaS"]','https://www.upplan.sg/up-adviser','vafwloQcnVzXT3SJAe3u2sWDdYAtmpTGhaVU0wUNuXQ');
