INSERT INTO "_content_pages" VALUES('pages/blog.yml','Latest Articles','{"title":"Latest Articles","description":"Thoughts on Vue, Nuxt, serverless architecture, and modern web development practices, and other stuff that gets my attention 👾."}','Thoughts on Vue, Nuxt, serverless architecture, and modern web development practices, and other stuff that gets my attention 👾.','yml',NULL,'{}','true','/blog','{"title":"Latest Articles","description":"Thoughts on Vue, Nuxt, serverless architecture, and modern web development practices, and other stuff that gets my attention 👾."}','blog','IS3DIblk2cnZpwbWdpOy-wNkgIrKasFmYRX0QHRuk_Y');
INSERT INTO "_content_about" VALUES('about/about.yml','About Me','{"title":"About Me","description":"A bit more about my journey as a full‑stack engineer and how I build scalable, user‑centric products.","profileImage":{"src":"/avatars/profile-image-2.png","alt":"Sean Erick C. Ramones"},"content":"Hi, I''m **Sean Erick Ramones**, a full‑stack software engineer with over 7 years of experience building modern, performant web applications.\n\nI focus on turning complex ideas into elegant, scalable products where design consistency, performance, and developer experience all click. On the frontend I prefer **Vue 3** and **Nuxt**; on the backend **Node.js** and **FastAPI**; for data, **PostgreSQL/Supabase**; and I deploy to modern serverless/cloud platforms like **Vercel** and **Cloudflare**.\n\n### What I care about\n\n- Type‑safe code and clean architecture\n- Reusable components and design systems\n- Performance, accessibility, and DX\n- CI/CD and code review culture that scales\n\n### Selected experience\n\n- Miller Development AB — Full‑stack Software Engineer (Hybrid, 2019–Present)\n- Better Trade Off Ltd. — Software Developer (Contract, 2023–2024)\n- SCI Global Services — Full‑stack Software Developer (On-site, 2018–2019)\n\n### Beyond the code\n\n- Running and cross‑fit training\n- Watching anime; reading Japanese manga/light novels\n- Playing MOBA games (**Dota 2**) and relaxing games (**Stardew Valley**)\n- Driving and exploring new places\n- Making espresso coffee and showing my (terrible) latte art to friends/colleagues.\n\nIf you’d like to collaborate, reach me at **seancramones@gmail.com** or connect on [LinkedIn](https://www.linkedin.com/in/sean-erick-ramones-102a64192).\n","images":[{"src":"/about/awareness-run-2024-dumagete.jpg","alt":"Awareness Run 2024 in Dumaguete"},{"src":"/about/job-agent-team-reunion-the-pub-dumaguete.jpg","alt":"Team reunion at The Pub in Dumaguete"},{"src":"/about/pad-thai-from-wok-bae-dumaguete.jpg","alt":"Pad Thai at Wok Bae in Dumaguete"},{"src":"/about/sipalay-beach-negros-occidental.jpg","alt":"Sipalay beach in Negros Occidental"},{"src":"/about/casaroro-falls-valencia-negros-oriental.jpg","alt":"Casaroro Falls in Negros Oriental"},{"src":"/about/sipalay-coast-negros-occidental.jpg","alt":"Sipalay coast in Negros Occidental"}],"now":{"openTo":["Full-time","Contract","Remote (UTC+8 overlap)"],"currently":["Building data-rich dashboards with Nuxt","Learning advanced serverless patterns"],"availability":"Accepting new projects now"}}','"Hi, I''m **Sean Erick Ramones**, a full‑stack software engineer with over 7 years of experience building modern, performant web applications.\n\nI focus on turning complex ideas into elegant, scalable products where design consistency, performance, and developer experience all click. On the frontend I prefer **Vue 3** and **Nuxt**; on the backend **Node.js** and **FastAPI**; for data, **PostgreSQL/Supabase**; and I deploy to modern serverless/cloud platforms like **Vercel** and **Cloudflare**.\n\n### What I care about\n\n- Type‑safe code and clean architecture\n- Reusable components and design systems\n- Performance, accessibility, and DX\n- CI/CD and code review culture that scales\n\n### Selected experience\n\n- Miller Development AB — Full‑stack Software Engineer (Hybrid, 2019–Present)\n- Better Trade Off Ltd. — Software Developer (Contract, 2023–2024)\n- SCI Global Services — Full‑stack Software Developer (On-site, 2018–2019)\n\n### Beyond the code\n\n- Running and cross‑fit training\n- Watching anime; reading Japanese manga/light novels\n- Playing MOBA games (**Dota 2**) and relaxing games (**Stardew Valley**)\n- Driving and exploring new places\n- Making espresso coffee and showing my (terrible) latte art to friends/colleagues.\n\nIf you’d like to collaborate, reach me at **seancramones@gmail.com** or connect on [LinkedIn](https://www.linkedin.com/in/sean-erick-ramones-102a64192).\n"','A bit more about my journey as a full‑stack engineer and how I build scalable, user‑centric products.','yml','[{"src":"/about/awareness-run-2024-dumagete.jpg","alt":"Awareness Run 2024 in Dumaguete"},{"src":"/about/job-agent-team-reunion-the-pub-dumaguete.jpg","alt":"Team reunion at The Pub in Dumaguete"},{"src":"/about/pad-thai-from-wok-bae-dumaguete.jpg","alt":"Pad Thai at Wok Bae in Dumaguete"},{"src":"/about/sipalay-beach-negros-occidental.jpg","alt":"Sipalay beach in Negros Occidental"},{"src":"/about/casaroro-falls-valencia-negros-oriental.jpg","alt":"Casaroro Falls in Negros Oriental"},{"src":"/about/sipalay-coast-negros-occidental.jpg","alt":"Sipalay coast in Negros Occidental"}]','{}','true','{"openTo":["Full-time","Contract","Remote (UTC+8 overlap)"],"currently":["Building data-rich dashboards with Nuxt","Learning advanced serverless patterns"],"availability":"Accepting new projects now"}','/about','{"src":"/avatars/profile-image-2.png","alt":"Sean Erick C. Ramones"}','{"title":"About Me","description":"A bit more about my journey as a full‑stack engineer and how I build scalable, user‑centric products."}','about','vBWzTamfQzliON4NyECwLRwKrig0Ji2sp160KQ-I48A');
INSERT INTO "_content_blog" VALUES('blog/blog/001.atomic-design-principles.md','[Vue][October 2024] - VueJS Introducing Dynamic Layouts using the Atomic Design Principles','{"name":"Sean Erick C. Ramones","avatar":{"src":"avatars/profile-image-1.png","alt":"Sean Erick C. Ramones"}}','{"type":"minimark","value":[["h1",{"id":"vueoctober-2024-vuejs-introducing-dynamic-layouts-using-the-atomic-design-principles"},"[Vue]",["span",{},"October 2024"]," - VueJS Introducing Dynamic Layouts using the Atomic Design Principles"],["p",{},"Sources: [",["a",{"href":"https://atomicdesign.bradfrost.com/chapter-2/","rel":["nofollow"]},"https://atomicdesign.bradfrost.com/chapter-2/"],", ",["a",{"href":"https://www.vuemastery.com/blog/dynamic-layouts-with-vue-jsx/#introducing-dynamic-layouts","rel":["nofollow"]},"https://www.vuemastery.com/blog/dynamic-layouts-with-vue-jsx/#introducing-dynamic-layouts"],"]"],["p",{},"For this month, Niclas - a frontend developer from the Sysarb SWE team has introduced a new architecture in the project client that can help scale and maintain the project better in the long-run."],["blockquote",{},["p",{},"The Problem: Fast-paced implementations but frequent changes in the UI."]],["p",{},"Creating UIs might be easy, but the hard part is maintaining them. The problem I frequently address when working on tasks during a sprint is mostly when there are scope changes - usually when I am currently working on. While we had moved to use a more centralized way of fetching and managing data thru the use of ",["code",{},"vue-composables"],"  and ",["code",{},"pinia-stores"]," , it doesn’t really help making the new changes fast since most of it involves the UI."],["blockquote",{},["p",{},"The Solution? Using Dynamic Template Layouts"]],["p",{},"Introducing the new atomic design principles, we can make views by abstracting them thru templates. This way we separate component-views to sections of the templates, and that way we also segregate certain data and reusability of certain parts. This helps us especially when there are new layout changes - if the changes are top-level layouts, we can easily move/create new templates and punch in the existing view-components."],["blockquote",{},["p",{},"The Down-sides of the approach"]],["p",{},"It involves another layer of abstraction in the view. Meaning you can’t create pages without declaring a template for it first. While this is helpful if you have different views with the same layout template, it is kind of redundant to add it if you only want a single-view template. But the thing here is that, we are prepared to move things around should there be new scope changes. And that saves us time 😄."],["h3",{"id":"take-away"},"Take-away"],["p",{},"Using ",["strong",{},"Atomic Design Principles"]," together with ",["code",{},"Dynamic Layout Templates"]," in this way allows you to create highly reusable and maintainable components and page-views, which are essential for scalable design systems in ",["code",{},"Vue.js"]," applications."],["p",{},"We are currently using this approach, and is somewhat of an experimental period. So far, it has worked, together with the ongoing migrations from foundation-css library to the new Bootstrap v5 library. I also think this will continue to help the client when the Sysarb UI Library is published by Niclas."]],"toc":{"title":"","searchDepth":2,"depth":2,"links":[{"id":"take-away","depth":3,"text":"Take-away"}]}}','2024-10-01T00:00:00.000Z','For this month, Niclas - a frontend developer from the Sysarb SWE team has introduced a new architecture in the project client that can help scale and maintain the project better in the long-run.','md','https://images.pexels.com/photos/256502/pexels-photo-256502.jpeg?auto=compress&cs=tinysrgb&h=650&w=940','{}',2,'true','/blog/atomic-design-principles','{"title":"[Vue][October 2024] - VueJS Introducing Dynamic Layouts using the Atomic Design Principles","description":"For this month, Niclas - a frontend developer from the Sysarb SWE team has introduced a new architecture in the project client that can help scale and maintain the project better in the long-run."}','blog/001.atomic-design-principles','4TngTq1-YaJ1tMF762G4gCVLUltBZVph1dYBN1NNZzI');
INSERT INTO "_content_blog" VALUES('blog/blog/002.understanding-js-and-its-quirks.md','[Javascript][November 2024] - Understanding JavaScript and Its Quirks','{"name":"Sean Erick C. Ramones","avatar":{"src":"avatars/profile-image-1.png","alt":"Sean Erick C. Ramones"}}','{"type":"minimark","value":[["h1",{"id":"javascriptnovember-2024-understanding-javascript-and-its-quirks"},"[Javascript]",["span",{},"November 2024"]," - Understanding JavaScript and Its Quirks"],["p",{},["em",{},"By Sean Erick C. Ramones, Vue SME | JavaScript/TypeScript SME"]],["p",{},"JavaScript is a powerful and widely used language, but it comes with quirks that can catch developers off guard (especially when you are new to the language). This report explores common pitfalls in JavaScript and provides insights to help developers navigate them effectively."],["h2",{"id":"automatic-semicolon-insertion-asi"},["strong",{},"Automatic Semicolon Insertion (ASI)"]],["p",{},"JavaScript automatically inserts semicolons at the end of some lines during code parsing. While this can make code appear simpler, it can also cause unintended behavior."],["p",{},["strong",{},"Example:"]],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"// Expected: a is 5\nlet a = 1\nlet b = 4\na\n++\nb // Treated as a separate expression\n\nconsole.log(a) // Outputs 1, not 5\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sHwdD"},"// Expected: a is 5\n"]],["span",{"class":"line","line":2},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," a "],["span",{"class":"sMK4o"},"="],["span",{"class":"sbssI"}," 1\n"]],["span",{"class":"line","line":3},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," b "],["span",{"class":"sMK4o"},"="],["span",{"class":"sbssI"}," 4\n"]],["span",{"class":"line","line":4},["span",{"class":"sTEyZ"},"a\n"]],["span",{"class":"line","line":5},["span",{"class":"sMK4o"},"++\n"]],["span",{"class":"line","line":6},["span",{"class":"sTEyZ"},"b "],["span",{"class":"sHwdD"},"// Treated as a separate expression\n"]],["span",{"class":"line","line":7},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":8},["span",{"class":"sTEyZ"},"console"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"log"],["span",{"class":"sTEyZ"},"(a) "],["span",{"class":"sHwdD"},"// Outputs 1, not 5\n"]]]],["p",{},["strong",{},"Explanation:"]],["p",{},"The parser interprets the ",["code",{},"++"]," as applying to ",["code",{},"b"]," on a new line, rather than continuing the operation on ",["code",{},"a"],". The example above is evaluated as:"],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"// Expected: a is 5\nlet a = 1\nlet b = 4\na; // <-- this line has a semicolon automatically inserted by ASI. The rest of the expression below is evaluated separately;\n++; // Treated as a separate expression.\nb; // also treated as a separate expression\n\nconsole.log(a) // Outputs 1, not 5\n\n// Correct way to do it would be:\na ++ b // <-- both should be on the same line;\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sHwdD"},"// Expected: a is 5\n"]],["span",{"class":"line","line":2},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," a "],["span",{"class":"sMK4o"},"="],["span",{"class":"sbssI"}," 1\n"]],["span",{"class":"line","line":3},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," b "],["span",{"class":"sMK4o"},"="],["span",{"class":"sbssI"}," 4\n"]],["span",{"class":"line","line":4},["span",{"class":"sTEyZ"},"a"],["span",{"class":"sMK4o"},";"],["span",{"class":"sHwdD"}," // <-- this line has a semicolon automatically inserted by ASI. The rest of the expression below is evaluated separately;\n"]],["span",{"class":"line","line":5},["span",{"class":"sMK4o"},"++;"],["span",{"class":"sHwdD"}," // Treated as a separate expression.\n"]],["span",{"class":"line","line":6},["span",{"class":"sTEyZ"},"b"],["span",{"class":"sMK4o"},";"],["span",{"class":"sHwdD"}," // also treated as a separate expression\n"]],["span",{"class":"line","line":7},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":8},["span",{"class":"sTEyZ"},"console"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"log"],["span",{"class":"sTEyZ"},"(a) "],["span",{"class":"sHwdD"},"// Outputs 1, not 5\n"]],["span",{"class":"line","line":9},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":10},["span",{"class":"sHwdD"},"// Correct way to do it would be:\n"]],["span",{"class":"line","line":11},["span",{"class":"sTEyZ"},"a "],["span",{"class":"sMK4o"},"++"],["span",{"class":"sTEyZ"}," b "],["span",{"class":"sHwdD"},"// <-- both should be on the same line;\n"]]]],["p",{},"The way to avoid this is to have them on the same line. And, while semicolons are technically optional in JavaScript, it’s going to hurt you in the long run to work with that concept."],["hr",{}],["h2",{"id":"arrays-with-non-sequential-keys"},["strong",{},"Arrays with Non-Sequential Keys"]],["p",{},"JavaScript arrays can have \"holes\" or even non-sequential keys, which can lead to surprising results when iterating."],["p",{},["strong",{},"Example:"]],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"javascript\nCopy code\nlet arr = [];\narr[3] = ''hello'';\n\nconsole.log(arr.length); // Outputs 4\nconsole.log(Object.keys(arr)); // Outputs [''3'']\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sTEyZ"},"javascript\n"]],["span",{"class":"line","line":2},["span",{"class":"sTEyZ"},"Copy code\n"]],["span",{"class":"line","line":3},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," arr "],["span",{"class":"sMK4o"},"="],["span",{"class":"sTEyZ"}," []"],["span",{"class":"sMK4o"},";\n"]],["span",{"class":"line","line":4},["span",{"class":"sTEyZ"},"arr["],["span",{"class":"sbssI"},"3"],["span",{"class":"sTEyZ"},"] "],["span",{"class":"sMK4o"},"="],["span",{"class":"sMK4o"}," ''"],["span",{"class":"sfazB"},"hello"],["span",{"class":"sMK4o"},"''"],["span",{"class":"sMK4o"},";\n"]],["span",{"class":"line","line":5},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":6},["span",{"class":"sTEyZ"},"console"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"log"],["span",{"class":"sTEyZ"},"(arr"],["span",{"class":"sMK4o"},"."],["span",{"class":"sTEyZ"},"length)"],["span",{"class":"sMK4o"},";"],["span",{"class":"sHwdD"}," // Outputs 4\n"]],["span",{"class":"line","line":7},["span",{"class":"sTEyZ"},"console"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"log"],["span",{"class":"sTEyZ"},"(Object"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"keys"],["span",{"class":"sTEyZ"},"(arr))"],["span",{"class":"sMK4o"},";"],["span",{"class":"sHwdD"}," // Outputs [''3'']\n"]]]],["p",{},["strong",{},"Explanation:"]],["p",{},"The array length is determined by the highest index + 1, but keys outside this sequence can still exist. For sanity’s sake, don’t do this, and instead use ",["code",{},"Array.prototype"]," functions."],["hr",{}],["h2",{"id":"adding-properties-to-primitives-are-ignored"},["strong",{},"Adding Properties to Primitives Are Ignored"]],["p",{},"Primitives like strings, numbers, and booleans are immutable, so adding properties to them doesn’t work as expected."],["p",{},["strong",{},"Example:"]],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"let str = \"hello\";\nstr.customProperty = \"world\";\n\nconsole.log(str.customProperty); // Outputs undefined\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"spNyl"},"let"],["span",{"class":"sTEyZ"}," str "],["span",{"class":"sMK4o"},"="],["span",{"class":"sMK4o"}," \""],["span",{"class":"sfazB"},"hello"],["span",{"class":"sMK4o"},"\""],["span",{"class":"sMK4o"},";\n"]],["span",{"class":"line","line":2},["span",{"class":"sTEyZ"},"str"],["span",{"class":"sMK4o"},"."],["span",{"class":"sTEyZ"},"customProperty "],["span",{"class":"sMK4o"},"="],["span",{"class":"sMK4o"}," \""],["span",{"class":"sfazB"},"world"],["span",{"class":"sMK4o"},"\""],["span",{"class":"sMK4o"},";\n"]],["span",{"class":"line","line":3},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":4},["span",{"class":"sTEyZ"},"console"],["span",{"class":"sMK4o"},"."],["span",{"class":"s2Zo4"},"log"],["span",{"class":"sTEyZ"},"(str"],["span",{"class":"sMK4o"},"."],["span",{"class":"sTEyZ"},"customProperty)"],["span",{"class":"sMK4o"},";"],["span",{"class":"sHwdD"}," // Outputs undefined\n"]]]],["p",{},["strong",{},"Explanation:"]],["p",{},"JavaScript temporarily wraps primitives in objects when properties are accessed, but the object is immediately discarded."],["hr",{}],["h2",{"id":"type-coercion"},["strong",{},"Type Coercion"]],["p",{},"JavaScript implicitly converts between types in certain operations, sometimes leading to unexpected results."],["p",{},["strong",{},"Example:"]],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"javascript\nCopy code\nconsole.log(''5'' - 2); // Outputs 3 (string coerced to number)\nconsole.log(''5'' + 2); // Outputs ''52'' (number coerced to string)\nconsole.log(false == 0); // Outputs true\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sTEyZ"},"javascript\n"]],["span",{"class":"line","line":2},["span",{"class":"sTEyZ"},"Copy code\n"]],["span",{"class":"line","line":3},["span",{"class":"sTEyZ"},"console"],["sp