INSERT INTO "_content_blog" VALUES('blog/blog/003.vue-js-experimental-vapor-mode.md','[Vue][November 2024] - Introducing Vue’s latest experimental Vapor Mode','{"name":"Sean Erick C. Ramones","avatar":{"src":"avatars/profile-image-1.png","alt":"Sean Erick C. Ramones"}}','{"type":"minimark","value":[["h1",{"id":"vuenovember-2024-introducing-vues-latest-experimental-vapor-mode"},"[Vue]",["span",{},"November 2024"]," - Introducing Vue’s latest experimental Vapor Mode"],["p",{},["em",{},"By Sean Erick C. Ramones, Vue SME | JavaScript/TypeScript SME"]],["h2",{"id":"overview"},["strong",{},"Overview"]],["p",{},"Vue.js is renowned for its approachable syntax and efficient runtime. However, as performance demands increase for UI-heavy or real-time applications, Vue has introduced ",["strong",{},"Vapor Mode"],". This experimental mode eliminates the virtual DOM (",["a",{"href":"https://vuejs.org/guide/extras/rendering-mechanism","rel":["nofollow"]},"vDOM"],") and pre-compiles templates for faster rendering, making it ideal for high-performance scenarios."],["hr",{}],["h3",{"id":"key-differences"},["strong",{},"Key Differences"]],["table",{},["thead",{},["tr",{},["th",{},"Feature"],["th",{},"Default Mode"],["th",{},"Vapor Mode"]]],["tbody",{},["tr",{},["td",{},["strong",{},"File Naming"]],["td",{},["code",{},".vue"]],["td",{},["code",{},".vapor.vue"]]],["tr",{},["td",{},["strong",{},"Syntax"]],["td",{},"Options API / Composition API"],["td",{},"Composition API"]],["tr",{},["td",{},["strong",{},"Virtual DOM"]],["td",{},"Uses vDOM for diffing and patching"],["td",{},"No vDOM; pre-compiles templates directly to DOM operations"]],["tr",{},["td",{},["strong",{},"Rendering"]],["td",{},"Runtime template compilation"],["td",{},"Direct DOM rendering (pre-compiled)"]],["tr",{},["td",{},["strong",{},"Reactivity"]],["td",{},"Fully reactive"],["td",{},"Manually managed (if needed)"]],["tr",{},["td",{},["strong",{},"Performance"]],["td",{},"General-purpose, suitable for most apps"],["td",{},"Optimized for performance-critical components"]]]],["hr",{}],["h3",{"id":"how-vapor-mode-works"},["strong",{},"How Vapor Mode Works"]],["p",{},"Vapor Mode removes the vDOM and instead relies on pre-compiled, direct DOM manipulation for rendering. By bypassing the vDOM diffing process, Vapor Mode eliminates the overhead of reconciling the virtual and actual DOM, making it faster for specific use cases."],["hr",{}],["h3",{"id":"syntax-and-usage"},["strong",{},"Syntax and Usage"]],["p",{},"The syntax in Vapor Mode is ",["strong",{},"almost identical"]," to the Composition API. The key difference lies in the file extension (",["code",{},".vapor.vue"],") and the optimizations applied during the build process."],["h3",{"id":"default-mode-example"},["strong",{},"Default Mode Example"]],["p",{},["em",{},"File: ",["code",{},"GraphComponent.vue"]]],["pre",{"className":"language-jsx shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"<template>\n  <svg :width=\"width\" :height=\"height\">\n    <polyline :points=\"points\" style=\"fill: none; stroke: blue;\" />\n  </svg>\n</template>\n\n<script setup>\nconst data = [10, 20, 30, 40, 50];\nconst width = 400, height = 200;\n\nconst points = data\n  .map((value, index) => `${index * 80},${200 - value * 3}`)\n  .join('' '');\n</script>\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sMK4o"},"<"],["span",{"class":"swJcz"},"template"],["span",{"class":"sMK4o"},">\n"]],["span",{"class":"line","line":2},["span",{"class":"sMK4o"},"  <"],["span",{"class":"swJcz"},"svg"],["span",{"class":"sMK4o"}," :width=\"width\" :height=\"height\">\n"]],["span",{"class":"line","line":3},["span",{"class":"sMK4o"},"    <polyline :points=\"points\" "],["span",{"class":"spNyl"},"style"],["span",{"class":"sMK4o"},"="],["span",{"class":"sMK4o"},"\""],["span",{"class":"sfazB"},"fill: none; stroke: blue;"],["span",{"class":"sMK4o"},"\""],["span",{"