ent .vue extension name!\n<template>\n  <svg :width=\"width\" :height=\"height\">\n    <polyline :points=\"points\" style=\"fill: none; stroke: blue;\" />\n  </svg>\n</template>\n\n<script setup>\nconst data = [10, 20, 30, 40, 50];\nconst width = 400, height = 200;\n\nconst points = data\n  .map((value, index) => `${index * 80},${200 - value * 3}`)\n  .join('' '');\n</script>\n","language":"jsx","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"sHwdD"},"// The very same code from above! Just with a different .vue extension name!\n"]],["span",{"class":"line","line":2},["span",{"class":"sMK4o"},"<"],["span",{"class":"swJcz"},"template"],["span",{"class":"sMK4o"},">\n"]],["span",{"class":"line","line":3},["span",{"class":"sMK4o"},"  <"],["span",{"class":"swJcz"},"svg"],["span",{"class":"sMK4o"}," :width=\"width\" :height=\"height\">\n"]],["span",{"class":"line","line":4},["span",{"class":"sMK4o"},"    <polyline :points=\"points\" "],["span",{"class":"spNyl"},"style"],["span",{"class":"sMK4o"},"="],["span",{"class":"sMK4o"},"\""],["span",{"class":"sfazB"},"fill: none; stroke: blue;"],["span",{"class":"sMK4o"},"\""],["span",{"class":"sMK4o"}," />\n"]],["span",{"class":"line","line":5},["span",{"class":"sMK4o"},"  </"],["span",{"class":"swJcz"},"svg"],["span",{"class":"sMK4o"},">\n"]],["span",{"class":"line","line":6},["span",{"class":"sMK4o"},"</"],["span",{"class":"sTEyZ"},"template"],["span",{"class":"sMK4o"},">\n"]],["span",{"class":"line","line":7},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":8},["span",{"class":"sMK4o"},"<"],["span",{"class":"swJcz"},"script"],["span",{"class":"spNyl"}," setup"],["span",{"class":"sMK4o"},">\n"]],["span",{"class":"line","line":9},["span",{"class":"sTEyZ"},"const data = [10, 20, 30, 40, 50];\n"]],["span",{"class":"line","line":10},["span",{"class":"sTEyZ"},"const width = 400, height = 200;\n"]],["span",{"class":"line","line":11},["span",{"emptyLinePlaceholder":true},"\n"]],["span",{"class":"line","line":12},["span",{"class":"sTEyZ"},"const points = data\n"]],["span",{"class":"line","line":13},["span",{"class":"sTEyZ"},"  .map((value, index) => `$"],["span",{"class":"sMK4o"},"{"],["span",{"class":"sTEyZ"},"index "],["span",{"class":"sMK4o"},"*"],["span",{"class":"sbssI"}," 80"],["span",{"class":"sMK4o"},"}"],["span",{"class":"sTEyZ"},",$"],["span",{"class":"sMK4o"},"{"],["span",{"class":"sbssI"},"200"],["span",{"class":"sMK4o"}," -"],["span",{"class":"sTEyZ"}," value "],["span",{"class":"sMK4o"},"*"],["span",{"class":"sbssI"}," 3"],["span",{"class":"sMK4o"},"}"],["span",{"class":"sTEyZ"},"`)\n"]],["span",{"class":"line","line":14},["span",{"class":"sTEyZ"},"  .join('' '');\n"]],["span",{"class":"line","line":15},["span",{"class":"sMK4o"},"</"],["span",{"class":"swJcz"},"script"],["span",{"class":"sMK4o"},">\n"]]]],["h3",{"id":"key-takeaway"},["strong",{},"Key Takeaway:"]],["p",{},"Vapor Mode eliminates the vDOM and uses direct DOM rendering. With ",["code",{},".vapor.vue"]," files, templates are compiled directly to DOM operations during the build step, with no runtime diffing."],["hr",{}],["h3",{"id":"benefits-of-eliminating-the-vdom"},["strong",{},"Benefits of Eliminating the vDOM"]],["ol",{},["li",{},["strong",{},"Improved Performance:"],["br",{}],"Vapor Mode avoids the computational cost of vDOM diffing and patching, making it faster for static or predictable UI updates."],["li",{},["strong",{},"Reduced Overhead:"],["br",{}],"The lack of vDOM simplifies rendering logic and reduces runtime memory usage, especially in complex or dynamic components."],["li",{},["strong",{},"Predictable Output:"],["br",{}],"Since templates are pre-compiled, the generated DOM structure is deterministic, leading to consistent performance."]],["hr",{}],["h3",{"id":"combining-default-mode-and-vapor-mode"},["strong",{},"Combining Default Mode and Vapor Mode"]],["p",{},"Default Mode and Vapor Mode can coexist within the same application. Use Default Mode for components requiring reactivity or dynamic behavior, and Vapor Mode for performance-critical components."],["p",{},"Example:"],["ul",{},["li",{},"Use Vapor Mode for a ",["strong",{},"real-time chart"],"."],["li",{},"Use Default Mode for ",["strong",{},"forms"]," or ",["strong",{},"interactive UI components"],"."]],["hr",{}],["h3",{"id":"when-to-use-vapor-mode"},["strong",{},"When to Use Vapor Mode?"]],["ul",{},["li",{},["strong",{},"High-Performance Applications"],": If your application requires high performance and low memory usage, Vapor Mode can be a good choice."],["li",{},["strong",{},"Simple Components"],": For simple components with minimal interactions and updates, Vapor Mode can provide a more efficient rendering process."],["li",{},["strong",{},"Specific Use Cases"],": If you have specific use cases where the benefits of Vapor Mode outweigh the limitations, it can be a valuable tool."]],["hr",{}],["h3",{"id":"limitations-and-considerations"},["strong",{},"Limitations and Considerations"]],["ol",{},["li",{},["strong",{},"Limited Features"],": Vapor Mode may not support all the features and optimizations provided by the standard Virtual DOM and Vue’s built-in features. This can limit its applicability in certain scenarios."],["li",{},["strong",{},"Compatibility"],": Some third-party libraries and plugins that rely on the Virtual DOM may not work correctly with Vapor Mode."],["li",{},["strong",{},"Debugging"],": Debugging issues related to rendering can be more challenging in Vapor Mode due to the reduced abstractions and optimizations."],["li",{},["strong",{},"Learning Curve"],": Developers familiar with the standard Virtual DOM may need to adjust their understanding and approach when working with Vapor Mode."]],["hr",{}],["h2",{"id":"final-thoughts"},["strong",{},"Final Thoughts"]],["p",{},"In most cases, Default Mode will remain our bread and butter—it’s reliable, flexible, and easy to use. Vapor Mode, on the other hand, is an exciting tool to explore for niche scenarios where performance is non-negotiable."],["p",{},"In the case for our project in ",["code",{},"Sysarb"]," we could use Vapor components for the ",["code",{},"graphs"]," since they are somewhat animation/data heavy as data-flow changes overtime. And the rest of the views (in this case the ",["code",{},"Dashboard"]," ) we can use the regular default modes."],["p",{},"Vapor Mode is still in the experimental phase and is not yet merged into vuejs/core. However, the outlook for a release in 2024 looks good."],["hr",{}],["p",{},["em",{},"Happy coding!"]," 🥲"],["style",{},"html pre.shiki code .sMK4o, html code.shiki .sMK4o{--shiki-light:#39ADB5;--shiki-default:#89DDFF;--shiki-dark:#89DDFF}html pre.shiki code .swJcz, html code.shiki .swJcz{--shiki-light:#E53935;--shiki-default:#F07178;--shiki-dark:#F07178}html pre.shiki code .spNyl, html code.shiki .spNyl{--shiki-light:#9C3EDA;--shiki-default:#C792EA;--shiki-dark:#C792EA}html pre.shiki code .sfazB, html code.shiki .sfazB{--shiki-light:#91B859;--shiki-default:#C3E88D;--shiki-dark:#C3E88D}html pre.shiki code .sTEyZ, html code.shiki .sTEyZ{--shiki-light:#90A4AE;--shiki-default:#EEFFFF;--shiki-dark:#BABED8}html pre.shiki code .sbssI, html code.shiki .sbssI{--shiki-light:#F76D47;--shiki-default:#F78C6C;--shiki-dark:#F78C6C}html .light .shiki span {color: var(--shiki-light);background: var(--shiki-light-bg);font-style: var(--shiki-light-font-style);font-weight: var(--shiki-light-font-weight);text-decoration: var(--shiki-light-text-decoration);}html.light .shiki span {color: var(--shiki-light);background: var(--shiki-light-bg);font-style: var(--shiki-light-font-style);font-weight: var(--shiki-light-font-weight);text-decoration: var(--shiki-light-text-decoration);}html .default .shiki span {color: var(--shiki-default);background: var(--shiki-default-bg);font-style: var(--shiki-default-font-style);font-weight: var(--shiki-default-font-weight);text-decoration: var(--shiki-default-text-decoration);}h