PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE _hub_migrations (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    name       TEXT UNIQUE,
    applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE _content_speaking (id TEXT PRIMARY KEY, "title" VARCHAR, "body" TEXT, "description" VARCHAR, "events" TEXT, "extension" VARCHAR, "links" TEXT, "meta" TEXT, "navigation" TEXT DEFAULT true, "path" VARCHAR, "seo" TEXT DEFAULT '{}', "stem" VARCHAR, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_info (id TEXT PRIMARY KEY, "ready" BOOLEAN, "structureVersion" VARCHAR, "version" VARCHAR, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_index (id TEXT PRIMARY KEY, "title" VARCHAR, "about" TEXT, "blog" TEXT, "body" TEXT, "description" VARCHAR, "experience" TEXT, "extension" VARCHAR, "faq" TEXT, "hero" TEXT, "meta" TEXT, "navigation" TEXT DEFAULT true, "now" TEXT NULL, "path" VARCHAR, "profileImage" TEXT, "seo" TEXT NULL, "snsLinks" TEXT, "stem" VARCHAR, "testimonials" TEXT, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_projects (id TEXT PRIMARY KEY, "title" VARCHAR, "date" DATE, "description" VARCHAR, "extension" VARCHAR, "image" VARCHAR, "meta" TEXT, "stem" VARCHAR, "tags" TEXT, "url" VARCHAR, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_pages (id TEXT PRIMARY KEY, "title" VARCHAR, "body" TEXT, "description" VARCHAR, "extension" VARCHAR, "links" TEXT, "meta" TEXT, "navigation" TEXT DEFAULT true, "path" VARCHAR, "seo" TEXT DEFAULT '{}', "stem" VARCHAR, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_about (id TEXT PRIMARY KEY, "title" VARCHAR, "body" TEXT, "content" TEXT, "description" VARCHAR, "extension" VARCHAR, "images" TEXT, "meta" TEXT, "navigation" TEXT DEFAULT true, "now" TEXT NULL, "path" VARCHAR, "profileImage" TEXT, "seo" TEXT DEFAULT '{}', "stem" VARCHAR, "__hash__" TEXT UNIQUE);
CREATE TABLE _content_blog (id TEXT PRIMARY KEY, "title" VARCHAR, "author" TEXT, "body" TEXT, "date" DATE, "description" VARCHAR, "extension" VARCHAR, "image" VARCHAR, "meta" TEXT, "minRead" INT, "navigation" TEXT DEFAULT true, "path" VARCHAR, "seo" TEXT DEFAULT '{}', "stem" VARCHAR, "__hash__" TEXT UNIQUE);
DELETE FROM sqlite_sequence;
